import { 
  FiCheckCircle, 
  FiXCircle, 
  FiAward, 
  FiCpu, 
  FiInfo, 
  FiClock, 
  FiArrowRight,
  FiAlertCircle
} from "react-icons/fi";
import { Link } from "react-router-dom";
import { useAuth } from "../../context/AuthContext";
import {
  Chart as ChartJS,
  RadialLinearScale,
  PointElement,
  LineElement,
  Filler,
  Tooltip,
  Legend,
} from 'chart.js';
import { Radar } from 'react-chartjs-2';

ChartJS.register(
  RadialLinearScale,
  PointElement,
  LineElement,
  Filler,
  Tooltip,
  Legend
);

const booleanFeature = (isTrue) => (
  <div className="flex justify-center">
    {isTrue ? (
      <FiCheckCircle className="text-emerald-500 w-5 h-5" />
    ) : (
      <FiXCircle className="text-red-400 w-5 h-5" />
    ) || <span className="text-gray-300">-</span>}
  </div>
);

export default function ComparisonResult({ result, id }) {
  const { user } = useAuth();

  if (!result) return null;

  const {
    products,
    comparisonScore,
    sustainabilityHighlights,
    comparisonGraph,
    aiVerdict,
    recommendations
  } = result;

  const p1 = products[0];
  const p2 = products[1];

  const chartOptions = {
    responsive: true,
    scales: {
      r: {
        angleLines: { color: 'rgba(0, 0, 0, 0.05)' },
        grid: { color: 'rgba(0, 0, 0, 0.05)' },
        pointLabels: {
          font: { size: 12, family: "'Inter', sans-serif" },
          color: '#4B5563'
        },
        ticks: { display: false, min: 0, max: 100 }
      }
    },
    plugins: {
      legend: {
        position: 'bottom',
        labels: { padding: 20, font: { size: 14 } }
      }
    }
  };

  // Modify backend colors to match our theme if necessary
  const formattedGraphData = comparisonGraph ? {
    labels: comparisonGraph.labels,
    datasets: comparisonGraph.datasets.map((dataset, i) => ({
      ...dataset,
      backgroundColor: i === 0 ? 'rgba(16, 185, 129, 0.2)' : 'rgba(99, 102, 241, 0.2)',
      borderColor: i === 0 ? '#10b981' : '#6366f1',
      pointBackgroundColor: i === 0 ? '#10b981' : '#6366f1',
      pointBorderColor: '#fff',
      pointHoverBackgroundColor: '#fff',
      pointHoverBorderColor: i === 0 ? '#10b981' : '#6366f1',
      borderWidth: 2,
    }))
  } : null;

  return (
    <div className="flex flex-col gap-8 animate-in fade-in zoom-in-95 duration-500">

      {/* Header Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {[p1, p2].map((p, index) => {
          const isWinner = comparisonScore.winner === p._id;
          return (
            <div 
              key={p._id || index} 
              className={`relative bg-white rounded-2xl shadow-sm border p-6 flex items-center gap-6 overflow-hidden ${
                isWinner ? 'border-emerald-400 shadow-emerald-100/50' : 'border-gray-100'
              }`}
            >
              {isWinner && (
                <div className="absolute -top-6 -right-6 w-24 h-24 bg-emerald-50 rounded-full flex items-end justify-start p-5">
                  <FiAward className="w-8 h-8 text-emerald-500" />
                </div>
              )}
              <div className="w-24 h-24 rounded-xl overflow-hidden bg-gray-50 flex-shrink-0 border border-gray-100">
                <img 
                  src={p.images && p.images[0] ? (p.images[0].url || p.images[0]) : "https://via.placeholder.com/100"} 
                  alt={p.name} 
                  className="w-full h-full object-cover"
                />
              </div>
              <div className="flex-1 pr-8">
                <div className="text-xs font-bold uppercase tracking-wider text-gray-400 mb-1">{p.brand}</div>
                <h3 className="text-xl font-bold text-gray-900 leading-tight mb-2">{p.name}</h3>
                <div className="inline-flex items-center gap-2 bg-gray-50 px-3 py-1.5 rounded-lg border border-gray-200">
                  <span className="text-xs text-gray-500 font-medium">Score:</span>
                  <span className={`text-lg font-bold ${isWinner ? 'text-emerald-600' : 'text-gray-700'}`}>
                    {index === 0 ? comparisonScore.product1Score : comparisonScore.product2Score}
                  </span>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Radar Chart */}
        {formattedGraphData && (
          <div className="lg:col-span-1 bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex flex-col items-center justify-center">
            <h4 className="text-lg font-bold text-gray-900 mb-6 self-start w-full border-b border-gray-100 pb-4">Performance Comparison</h4>
            <div className="w-full max-w-sm aspect-square">
              <Radar data={formattedGraphData} options={chartOptions} />
            </div>
          </div>
        )}

        {/* Detailed Metrics Table */}
        <div className={`bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden ${formattedGraphData ? 'lg:col-span-2' : 'lg:col-span-3'}`}>
          <div className="p-6 border-b border-gray-100">
             <h4 className="text-lg font-bold text-gray-900">Metrics Breakdown</h4>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-gray-50">
                  <th className="p-4 font-semibold text-gray-600 border-b border-gray-200 text-sm">Feature</th>
                  <th className="p-4 font-bold text-emerald-700 border-b border-gray-200 text-center w-1/3">{p1.name}</th>
                  <th className="p-4 font-bold text-indigo-700 border-b border-gray-200 text-center w-1/3">{p2.name}</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100 bg-white">
                <tr>
                  <td className="p-4 text-sm font-medium text-gray-700">Recyclable</td>
                  <td className="p-4 text-center">{booleanFeature(p1.sustainability?.recyclableMaterial)}</td>
                  <td className="p-4 text-center">{booleanFeature(p2.sustainability?.recyclableMaterial)}</td>
                </tr>
                <tr>
                  <td className="p-4 text-sm font-medium text-gray-700">Biodegradable</td>
                  <td className="p-4 text-center">{booleanFeature(p1.sustainability?.biodegradable)}</td>
                  <td className="p-4 text-center">{booleanFeature(p2.sustainability?.biodegradable)}</td>
                </tr>
                <tr>
                  <td className="p-4 text-sm font-medium text-gray-700">Plastic Free</td>
                  <td className="p-4 text-center">{booleanFeature(p1.sustainability?.plasticFree)}</td>
                  <td className="p-4 text-center">{booleanFeature(p2.sustainability?.plasticFree)}</td>
                </tr>
                <tr>
                  <td className="p-4 text-sm font-medium text-gray-700">Cruelty Free</td>
                  <td className="p-4 text-center">{booleanFeature(p1.sustainability?.crueltyFree)}</td>
                  <td className="p-4 text-center">{booleanFeature(p2.sustainability?.crueltyFree)}</td>
                </tr>
                <tr>
                  <td className="p-4 text-sm font-medium text-gray-700">Carbon Footprint</td>
                  <td className="p-4 text-center text-sm font-bold text-emerald-600 bg-emerald-50/30">
                    {p1.sustainability?.carbonFootprint ? `${p1.sustainability.carbonFootprint} kg` : '-'}
                  </td>
                  <td className="p-4 text-center text-sm font-bold text-indigo-600 bg-indigo-50/30">
                    {p2.sustainability?.carbonFootprint ? `${p2.sustainability.carbonFootprint} kg` : '-'}
                  </td>
                </tr>
              </tbody>
            </table>
          </div>
        </div>
      </div>

      {/* Highlights & Verdict */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">

        {/* Left Column: Advantages */}
        <div className="flex flex-col gap-6">
          {(sustainabilityHighlights?.product1Advantages?.length > 0 || sustainabilityHighlights?.product2Advantages?.length > 0) && (
            <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
              <h4 className="text-lg font-bold text-gray-900 mb-6">Key Advantages</h4>
              <div className="space-y-6">
                {sustainabilityHighlights.product1Advantages?.length > 0 && (
                  <div>
                    <h5 className="text-sm font-bold text-emerald-700 uppercase tracking-widest mb-3">{p1.name}</h5>
                    <ul className="space-y-2">
                      {sustainabilityHighlights.product1Advantages.map((adv, i) => (
                        <li key={i} className="flex items-start gap-2 text-sm text-gray-600">
                          <FiCheckCircle className="text-emerald-500 w-4 h-4 mt-0.5 flex-shrink-0" />
                          <span>{adv}</span>
                        </li>
                      ))}
                    </ul>
                  </div>
                )}
                {sustainabilityHighlights.product2Advantages?.length > 0 && (
                  <div>
                    <h5 className="text-sm font-bold text-indigo-700 uppercase tracking-widest mb-3">{p2.name}</h5>
                    <ul className="space-y-2">
                      {sustainabilityHighlights.product2Advantages.map((adv, i) => (
                        <li key={i} className="flex items-start gap-2 text-sm text-gray-600">
                          <FiCheckCircle className="text-indigo-400 w-4 h-4 mt-0.5 flex-shrink-0" />
                          <span>{adv}</span>
                        </li>
                      ))}
                    </ul>
                  </div>
                )}
              </div>
            </div>
          )}

          {/* Recommendations if any */}
          {recommendations && (
             <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
               <h4 className="text-lg font-bold text-gray-900 mb-6">Recommendations</h4>

               {recommendations.general?.length > 0 && (
                 <div className="mb-4 bg-gray-50 border border-gray-200 p-4 rounded-xl">
                   <div className="flex items-center gap-2 mb-2 text-gray-800 font-semibold text-sm">
                     <FiInfo className="text-gray-500"/> General Insights
                   </div>
                   <ul className="list-disc pl-5 space-y-1 text-sm text-gray-600">
                     {recommendations.general.map((rec, i) => <li key={i}>{rec}</li>)}
                   </ul>
                 </div>
               )}

               <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                 {recommendations.product1Suggestions?.length > 0 && (
                   <div className="border border-emerald-100 bg-emerald-50/30 p-4 rounded-xl">
                      <h5 className="text-xs font-bold text-emerald-700 uppercase mb-2 line-clamp-1" title={`For ${p1.name}`}>For {p1.name}</h5>
                      <ul className="space-y-1 text-sm text-gray-600 list-disc pl-4">
                        {recommendations.product1Suggestions.map((rec, i) => <li key={i}>{rec}</li>)}
                      </ul>
                   </div>
                 )}
                 {recommendations.product2Suggestions?.length > 0 && (
                   <div className="border border-indigo-100 bg-indigo-50/30 p-4 rounded-xl">
                      <h5 className="text-xs font-bold text-indigo-700 uppercase mb-2 line-clamp-1" title={`For ${p2.name}`}>For {p2.name}</h5>
                      <ul className="space-y-1 text-sm text-gray-600 list-disc pl-4">
                        {recommendations.product2Suggestions.map((rec, i) => <li key={i}>{rec}</li>)}
                      </ul>
                   </div>
                 )}
               </div>
             </div>
          )}
        </div>

        {/* Right Column: AI Verdict */}
        <div className="h-full">
          <div className="h-full rounded-2xl shadow-lg border border-purple-200 bg-gradient-to-br from-indigo-900 via-purple-900 to-fuchsia-900 p-8 flex flex-col items-center justify-center text-center relative overflow-hidden">
            {/* Glassmorphism decoration */}
            <div className="absolute top-0 right-0 w-64 h-64 bg-white/5 rounded-full blur-3xl -translate-y-1/2 translate-x-1/2"></div>
            <div className="absolute bottom-0 left-0 w-64 h-64 bg-purple-500/10 rounded-full blur-3xl translate-y-1/2 -translate-x-1/2"></div>

            <div className="relative z-10 w-16 h-16 bg-white/10 backdrop-blur-md rounded-2xl flex items-center justify-center mb-6 shadow-xl border border-white/20">
              <FiCpu className="w-8 h-8 text-purple-200" />
            </div>
            <h4 className="relative z-10 text-2xl font-black text-white tracking-widest uppercase mb-6">AI Verdict</h4>
            <div className="relative z-10 text-lg text-purple-100 leading-relaxed max-w-md mx-auto italic font-light font-serif">
              "{aiVerdict}"
            </div>
          </div>
        </div>

      </div>

      {/* Footer Actions */}
      <div className="flex flex-col sm:flex-row items-center justify-between bg-white rounded-2xl shadow-sm border border-gray-100 p-6 mt-4">
        <div className="flex items-center gap-3 text-gray-500 text-sm mb-4 sm:mb-0">
          <FiAlertCircle className="w-5 h-5 text-emerald-500"/>
          {user ? (
            <span>This comparison was automatically saved to your history.</span>
          ) : (
            <span>Register an account to automatically save your comparisons.</span>
          )}
        </div>

        <div className="flex gap-4">
          {user && (
            <Link
              to="/compare/history"
              className="px-6 py-2.5 bg-gray-50 hover:bg-gray-100 border border-gray-200 text-gray-700 rounded-xl font-medium transition-colors flex items-center gap-2"
            >
              <FiClock /> View in History
            </Link>
          )}
          <Link
            to="/compare"
            onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })} // if already on /compare, it just scrolls up. Better UX.
            className="px-6 py-2.5 bg-emerald-600 hover:bg-emerald-700 text-white rounded-xl font-bold transition-shadow shadow-md flex items-center gap-2"
          >
            New Comparison <FiArrowRight />
          </Link>
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect, useRef } from "react";
import { FiSearch, FiPackage, FiZap, FiX, FiCheck } from "react-icons/fi";
import { searchProducts } from "../../services/productServices";
import toast from "react-hot-toast";

export default function ComparisonSelector({ onCompare, onQuickCompare, isLoading }) {
  const [mode, setMode] = useState("standard"); // 'standard' or 'quick'

  // Standard Mode State
  const [search1, setSearch1] = useState("");
  const [search2, setSearch2] = useState("");
  const [results1, setResults1] = useState([]);
  const [results2, setResults2] = useState([]);
  const [selected1, setSelected1] = useState(null);
  const [selected2, setSelected2] = useState(null);
  const [isSearching1, setIsSearching1] = useState(false);
  const [isSearching2, setIsSearching2] = useState(false);

  // Quick Compare Mode State
  const [quickName1, setQuickName1] = useState("");
  const [quickName2, setQuickName2] = useState("");

  const timeout1Ref = useRef(null);
  const timeout2Ref = useRef(null);

  const handleSearch = async (query, setResults, setIsSearching) => {
    if (!query.trim()) {
      setResults([]);
      return;
    }
    setIsSearching(true);
    try {
      const response = await searchProducts(query);
      if (response.success) {
        setResults(Array.isArray(response.data) ? response.data : [response.data]);
      } else {
        setResults([]);
      }
    } catch (error) {
      console.error("Error searching products:", error);
      setResults([]);
    } finally {
      setIsSearching(false);
    }
  };

  const onSearch1Change = (e) => {
    const val = e.target.value;
    setSearch1(val);
    if (selected1) setSelected1(null);

    if (timeout1Ref.current) clearTimeout(timeout1Ref.current);
    timeout1Ref.current = setTimeout(() => {
      handleSearch(val, setResults1, setIsSearching1);
    }, 400);
  };

  const onSearch2Change = (e) => {
    const val = e.target.value;
    setSearch2(val);
    if (selected2) setSelected2(null);

    if (timeout2Ref.current) clearTimeout(timeout2Ref.current);
    timeout2Ref.current = setTimeout(() => {
      handleSearch(val, setResults2, setIsSearching2);
    }, 400);
  };

  const handleSelect1 = (product) => {
    if (selected2 && selected2._id === product._id) {
      toast.error("You cannot compare the same product.");
      return;
    }
    setSelected1(product);
    setSearch1(product.name);
    setResults1([]);
  };

  const handleSelect2 = (product) => {
    if (selected1 && selected1._id === product._id) {
      toast.error("You cannot compare the same product.");
      return;
    }
    setSelected2(product);
    setSearch2(product.name);
    setResults2([]);
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (mode === "standard") {
      if (!selected1 || !selected2) {
        toast.error("Please select two products to compare.");
        return;
      }
      if (selected1._id === selected2._id) {
        toast.error("Cannot compare the same product.");
        return;
      }
      onCompare(selected1._id, selected2._id);
    } else {
      if (!quickName1.trim() || !quickName2.trim()) {
        toast.error("Please enter names for both products.");
        return;
      }
      onQuickCompare(quickName1, quickName2);
    }
  };

  const SearchInput = ({ 
    label, 
    value, 
    onChange, 
    results, 
    onSelect, 
    selected, 
    isSearching 
  }) => (
    <div className="relative flex-1">
      <label className="block text-sm font-medium text-gray-700 mb-1">{label}</label>
      <div className="relative">
        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
          {selected ? <FiCheck className="text-emerald-500" /> : <FiSearch className="text-gray-400" />}
        </div>
        <input
          type="text"
          value={value}
          onChange={onChange}
          disabled={isLoading}
          placeholder={`Search ${label.toLowerCase()}...`}
          className="pl-10 pr-4 py-3 w-full rounded-xl border border-gray-200 focus:ring-2 focus:ring-emerald-500 focus:outline-none transition-shadow bg-white"
        />
        {selected && (
          <button
            type="button"
            onClick={() => {
              onChange({ target: { value: "" } });
            }}
            className="absolute inset-y-0 right-0 pr-3 flex items-center text-gray-400 hover:text-gray-600"
          >
            <FiX />
          </button>
        )}
      </div>

      {/* Autocomplete Dropdown */}
      {!selected && results.length > 0 && (
        <div className="absolute z-10 w-full mt-1 bg-white rounded-xl shadow-lg border border-gray-100 max-h-60 overflow-auto">
          {results.map((product) => (
            <div
              key={product._id}
              onClick={() => onSelect(product)}
              className="flex items-center gap-3 p-3 hover:bg-emerald-50 cursor-pointer border-b border-gray-50 last:border-0 transition-colors"
            >
              <div className="w-10 h-10 bg-gray-100 rounded-lg overflow-hidden shrink-0">
                <img
                  src={product.images && product.images[0] ? (product.images[0].url || product.images[0]) : "https://via.placeholder.com/40"}
                  alt={product.name}
                  className="w-full h-full object-cover"
                />
              </div>
              <div className="truncate text-sm">
                <p className="font-bold text-gray-900 truncate">{product.name}</p>
                <p className="text-xs text-gray-500 truncate">{product.brand}</p>
              </div>
            </div>
          ))}
        </div>
      )}
      {isSearching && !selected && (
        <div className="absolute z-10 w-full mt-1 bg-white rounded-xl shadow-lg border border-gray-100 p-3 text-center text-sm text-gray-500">
          Searching...
        </div>
      )}
    </div>
  );

  return (
    <div className="bg-white/80 backdrop-blur-md rounded-2xl shadow-sm border border-gray-100 p-6 md:p-8">
      {/* Mode Switcher */}
      <div className="flex justify-center mb-8">
        <div className="bg-gray-100 p-1 rounded-xl inline-flex shadow-inner">
          <button
            type="button"
            onClick={() => setMode("standard")}
            className={`px-6 py-2 rounded-lg text-sm font-medium transition-all ${
              mode === "standard"
                ? "bg-white text-emerald-700 shadow-sm"
                : "text-gray-500 hover:text-gray-700"
            }`}
          >
            <span className="flex items-center gap-2">
              <FiPackage /> Database Search
            </span>
          </button>
          <button
            type="button"
            onClick={() => setMode("quick")}
            className={`px-6 py-2 rounded-lg text-sm font-medium transition-all ${
              mode === "quick"
                ? "bg-white text-indigo-700 shadow-sm"
                : "text-gray-500 hover:text-gray-700"
            }`}
          >
            <span className="flex items-center gap-2">
              <FiZap /> Quick Name Match
            </span>
          </button>
        </div>
      </div>

      <form onSubmit={handleSubmit}>
        <div className="flex flex-col md:flex-row gap-6 items-start">
          {mode === "standard" ? (
            <>
              <SearchInput
                label="Product 1"
                value={search1}
                onChange={onSearch1Change}
                results={results1}
                onSelect={handleSelect1}
                selected={selected1}
                isSearching={isSearching1}
              />
              <div className="hidden md:flex pt-8 items-center justify-center font-bold text-gray-300 px-4">
                VS
              </div>
              <SearchInput
                label="Product 2"
                value={search2}
                onChange={onSearch2Change}
                results={results2}
                onSelect={handleSelect2}
                selected={selected2}
                isSearching={isSearching2}
              />
            </>
          ) : (
            <>
              <div className="flex-1">
                <label className="block text-sm font-medium text-gray-700 mb-1">Product 1 Name</label>
                <input
                  type="text"
                  value={quickName1}
                  onChange={(e) => setQuickName1(e.target.value)}
                  disabled={isLoading}
                  placeholder="E.g., Bamboo Toothbrush"
                  className="px-4 py-3 w-full rounded-xl border border-gray-200 focus:ring-2 focus:ring-indigo-500 focus:outline-none transition-shadow bg-white"
                />
              </div>
              <div className="hidden md:flex pt-8 items-center justify-center font-bold text-gray-300 px-4">
                VS
              </div>
              <div className="flex-1">
                <label className="block text-sm font-medium text-gray-700 mb-1">Product 2 Name</label>
                <input
                  type="text"
                  value={quickName2}
                  onChange={(e) => setQuickName2(e.target.value)}
                  disabled={isLoading}
                  placeholder="E.g., Plastic Toothbrush"
                  className="px-4 py-3 w-full rounded-xl border border-gray-200 focus:ring-2 focus:ring-indigo-500 focus:outline-none transition-shadow bg-white"
                />
              </div>
            </>
          )}
        </div>

        <div className="mt-8 flex justify-center">
          <button
            type="submit"
            disabled={isLoading || (mode === 'standard' && (!selected1 || !selected2 || selected1._id === selected2._id))}
            className={`px-8 py-3 rounded-xl font-bold transition-all shadow-md flex items-center justify-center min-w-[200px] ${
              isLoading || (mode === 'standard' && (!selected1 || !selected2 || selected1._id === selected2._id))
                ? "bg-gray-300 text-gray-100 cursor-not-allowed"
                : mode === "standard"
                ? "bg-emerald-600 hover:bg-emerald-700 text-white hover:shadow-lg"
                : "bg-indigo-600 hover:bg-indigo-700 text-white hover:shadow-lg"
            }`}
          >
            {isLoading ? "Analyzing..." : "Compare Products"}
          </button>
        </div>
      </form>
    </div>
  );
}

import { useState } from "react";
import { addProduct } from "../../services/productServices";
import { FiUploadCloud, FiX, FiCheck, FiLoader } from "react-icons/fi";
import { useNavigate } from "react-router-dom";

export default function AddProductForm() {
  const navigate = useNavigate();
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [successMessage, setSuccessMessage] = useState("");
  const [errorMessage, setErrorMessage] = useState("");
  const [isCustomCategory, setIsCustomCategory] = useState(false);

  const PREDEFINED_CATEGORIES = [
    "Electronics",
    "Fashion & Apparel",
    "Home & Living",
    "Beauty & Health",
    "Food & Groceries",
  ];

  const [formData, setFormData] = useState({
    name: "",
    brand: "",
    category: "",
    description: "",
    images: [],
    sustainability: {
      recyclableMaterial: true,
      biodegradable: false,
      plasticFree: false,
      carbonFootprint: 0,
      crueltyFree: true,
      fairTradeCertified: false,
      renewableEnergyUsed: true,
      energyEfficiencyRating: 5,
    },
  });

  const [imagePreviews, setImagePreviews] = useState([]);

  const handleTextChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleSustainabilityChange = (name, value) => {
    setFormData((prev) => ({
      ...prev,
      sustainability: {
        ...prev.sustainability,
        [name]: value,
      },
    }));
  };

  const handleImageChange = (e) => {
    const files = Array.from(e.target.files);

    setFormData((prev) => ({
      ...prev,
      images: [...prev.images, ...files],
    }));

    const newPreviews = files.map((file) => URL.createObjectURL(file));
    setImagePreviews((prev) => [...prev, ...newPreviews]);
  };

  const removeImage = (index) => {
    setFormData((prev) => {
      const newImages = [...prev.images];
      newImages.splice(index, 1);
      return { ...prev, images: newImages };
    });

    setImagePreviews((prev) => {
      const newPreviews = [...prev];
      URL.revokeObjectURL(newPreviews[index]); // clean up
      newPreviews.splice(index, 1);
      return newPreviews;
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);
    setSuccessMessage("");
    setErrorMessage("");

    try {
      const submitData = new FormData();
      submitData.append("name", formData.name);
      submitData.append("brand", formData.brand);
      submitData.append("category", formData.category);
      submitData.append("description", formData.description);

      formData.images.forEach((img) => {
        submitData.append("images", img);
      });

      // Send sustainability as a JSON string. The backend will parse it.
      submitData.append(
        "sustainability",
        JSON.stringify(formData.sustainability)
      );

      const response = await addProduct(submitData);
      setSuccessMessage("Product added successfully! Redirecting...");
      setTimeout(() => {
        navigate("/products");
      }, 1500);
    } catch (error) {
      console.error("Error submitting:", error);
      setErrorMessage(
        error.response?.data?.message || "Failed to add product. Please try again."
      );
    } finally {
      setIsSubmitting(false);
    }
  };

  const toggleClasses = (checked) =>
    `relative inline-flex h-6 w-11 flex-shrink-0 cursor-pointer rounded-full border-2 border-transparent transition-colors duration-200 ease-in-out focus:outline-none focus:ring-2 focus:ring-emerald-500 focus:ring-offset-2 ${
      checked ? "bg-emerald-600" : "bg-gray-200"
    }`;

  const togglePinClasses = (checked) =>
    `pointer-events-none inline-block h-5 w-5 transform rounded-full bg-white shadow ring-0 transition duration-200 ease-in-out ${
      checked ? "translate-x-5" : "translate-x-0"
    }`;

  return (
    <form onSubmit={handleSubmit} className="space-y-8">
      {successMessage && (
        <div className="p-4 bg-emerald-50 border border-emerald-200 rounded-xl flex items-center gap-3 text-emerald-800">
          <FiCheck className="w-5 h-5" />
          <span className="font-medium">{successMessage}</span>
        </div>
      )}
      {errorMessage && (
        <div className="p-4 bg-red-50 border border-red-200 rounded-xl flex items-center gap-3 text-red-800">
          <FiX className="w-5 h-5" />
          <span className="font-medium">{errorMessage}</span>
        </div>
      )}

      {/* Grid for basic info */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div>
          <label className="block text-sm font-semibold text-gray-700 mb-1">
            Product Name
          </label>
          <input
            type="text"
            name="name"
            required
            value={formData.name}
            onChange={handleTextChange}
            className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 transition-shadow text-gray-900 bg-gray-50/50"
            placeholder="e.g. SolarCharg"
          />
        </div>
        <div>
          <label className="block text-sm font-semibold text-gray-700 mb-1">
            Brand
          </label>
          <input
            type="text"
            name="brand"
            required
            value={formData.brand}
            onChange={handleTextChange}
            className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 transition-shadow text-gray-900 bg-gray-50/50"
            placeholder="e.g. SunTech"
          />
        </div>
        <div>
          <label className="block text-sm font-semibold text-gray-700 mb-1">
            Category
          </label>
          <select
            name="categorySelect"
            required={!isCustomCategory}
            value={PREDEFINED_CATEGORIES.includes(formData.category) ? formData.category : (isCustomCategory ? "Other" : "")}
            onChange={(e) => {
              if (e.target.value === "Other") {
                setFormData((prev) => ({ ...prev, category: "" }));
                setIsCustomCategory(true);
              } else {
                setFormData((prev) => ({ ...prev, category: e.target.value }));
                setIsCustomCategory(false);
              }
            }}
            className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 transition-shadow text-gray-900 bg-gray-50/50"
          >
            <option value="" disabled>Select a Category</option>
            {PREDEFINED_CATEGORIES.map(cat => (
              <option key={cat} value={cat}>{cat}</option>
            ))}
            <option value="Other">Add New Category...</option>
          </select>
          {isCustomCategory && (
            <input
              type="text"
              name="category"
              required
              value={formData.category}
              onChange={handleTextChange}
              className="mt-3 w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 transition-shadow text-gray-900 bg-gray-50/50"
              placeholder="Type new category..."
              autoFocus
            />
          )}
        </div>
        <div className="md:col-span-2">
          <label className="block text-sm font-semibold text-gray-700 mb-1">
            Description
          </label>
          <textarea
            name="description"
            rows={3}
            required
            value={formData.description}
            onChange={handleTextChange}
            className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 transition-shadow text-gray-900 bg-gray-50/50 resize-none"
            placeholder="Describe the product and its primary purpose..."
          />
        </div>
      </div>

      <hr className="border-gray-100" />

      {/* Image Upload Area */}
      <div>
        <label className="block text-sm font-semibold text-gray-700 mb-3">
          Product Images
        </label>
        <div className="flex justify-center rounded-xl border border-dashed border-gray-300 px-6 py-8 bg-gray-50 hover:bg-gray-100 transition-colors">
          <div className="text-center">
            <FiUploadCloud className="mx-auto h-10 w-10 text-gray-400" aria-hidden="true" />
            <div className="mt-4 flex text-sm leading-6 text-gray-600 justify-center">
              <label className="relative cursor-pointer rounded-md bg-transparent font-semibold text-emerald-600 focus-within:outline-none focus-within:ring-2 focus-within:ring-emerald-600 focus-within:ring-offset-2 hover:text-emerald-500">
                <span>Upload a file</span>
                <input
                  type="file"
                  multiple
                  accept="image/*"
                  className="sr-only"
                  onChange={handleImageChange}
                />
              </label>
              <p className="pl-1">or drag and drop</p>
            </div>
            <p className="text-xs leading-5 text-gray-500">PNG, JPG up to 5MB</p>
          </div>
        </div>

        {/* Image Previews */}
        {imagePreviews.length > 0 && (
          <div className="mt-4 grid grid-cols-2 gap-4 sm:grid-cols-3 md:grid-cols-4">
            {imagePreviews.map((url, i) => (
              <div key={i} className="relative group rounded-xl overflow-hidden shadow-sm border border-gray-200">
                <img
                  src={url}
                  alt={`Preview ${i}`}
                  className="h-24 w-full object-cover"
                />
                <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                  <button
                    type="button"
                    onClick={() => removeImage(i)}
                    className="p-1.5 bg-red-500 hover:bg-red-600 text-white rounded-full transition-colors"
                  >
                    <FiX size={16} />
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      <hr className="border-gray-100" />

      {/* Sustainability Section */}
      <div>
        <h3 className="text-xl font-bold text-gray-900 mb-6 flex items-center gap-2">
          <span className="p-1.5 bg-lime-100 text-lime-700 rounded-lg">🌱</span>
          Sustainability Metrics
        </h3>

        <div className="grid grid-cols-1 sm:grid-cols-2 gap-x-8 gap-y-6">
          {/* Toggles */}
          {[
            { key: "recyclableMaterial", label: "Recyclable Material" },
            { key: "biodegradable", label: "Biodegradable" },
            { key: "plasticFree", label: "Plastic Free" },
            { key: "crueltyFree", label: "Cruelty Free" },
            { key: "fairTradeCertified", label: "Fair Trade Certified" },
            { key: "renewableEnergyUsed", label: "Renewable Energy Used" },
          ].map((item) => (
            <div key={item.key} className="flex items-center justify-between">
              <span className="flex flex-col">
                <span className="text-sm font-medium leading-6 text-gray-900">
                  {item.label}
                </span>
              </span>
              <button
                type="button"
                className={toggleClasses(formData.sustainability[item.key])}
                onClick={() =>
                  handleSustainabilityChange(
                    item.key,
                    !formData.sustainability[item.key]
                  )
                }
              >
                <span className={togglePinClasses(formData.sustainability[item.key])} />
              </button>
            </div>
          ))}

          {/* Number Inputs */}
          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-1">
              Carbon Footprint (kg CO2e)
            </label>
            <input
              type="number"
              step="0.1"
              value={formData.sustainability.carbonFootprint}
              onChange={(e) =>
                handleSustainabilityChange(
                  "carbonFootprint",
                  Number(e.target.value)
                )
              }
              className="w-full px-4 py-2.5 rounded-xl border border-gray-200 focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 bg-gray-50/50"
            />
          </div>

          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-1">
              Energy Efficiency Rating (1-5)
            </label>
            <input
              type="number"
              min="1"
              max="5"
              step="1"
              value={formData.sustainability.energyEfficiencyRating}
              onChange={(e) =>
                handleSustainabilityChange(
                  "energyEfficiencyRating",
                  Number(e.target.value)
                )
              }
              className="w-full px-4 py-2.5 rounded-xl border border-gray-200 focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 bg-gray-50/50"
            />
          </div>
        </div>
      </div>

      <div className="pt-4">
        <button
          type="submit"
          disabled={isSubmitting}
          className="w-full flex items-center justify-center py-3.5 px-4 rounded-xl text-white font-semibold text-lg bg-emerald-600 hover:bg-emerald-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-emerald-500 disabled:opacity-70 disabled:cursor-not-allowed transition-all shadow-md hover:shadow-lg"
        >
          {isSubmitting ? (
            <>
              <FiLoader className="animate-spin -ml-1 mr-2 h-5 w-5 text-white" />
              Adding Product...
            </>
          ) : (
            "Add Product"
          )}
        </button>
      </div>
    </form>
  );
}

import { useState, useEffect } from "react";
import { updateProduct, getProductById } from "../../services/productServices";
import { FiUploadCloud, FiX, FiCheck, FiLoader } from "react-icons/fi";
import { useNavigate, useParams } from "react-router-dom";

export default function EditProductForm() {
  const navigate = useNavigate();
  const { id } = useParams();
  
  const [isLoading, setIsLoading] = useState(true);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [successMessage, setSuccessMessage] = useState("");
  const [errorMessage, setErrorMessage] = useState("");
  const [isCustomCategory, setIsCustomCategory] = useState(false);

  const PREDEFINED_CATEGORIES = [
    "Electronics",
    "Fashion & Apparel",
    "Home & Living",
    "Beauty & Health",
    "Food & Groceries",
  ];

  const [formData, setFormData] = useState({
    name: "",
    brand: "",
    category: "",
    description: "",
    images: [],
    sustainability: {
      recyclableMaterial: true,
      biodegradable: false,
      plasticFree: false,
      carbonFootprint: 0,
      crueltyFree: true,
      fairTradeCertified: false,
      renewableEnergyUsed: true,
      energyEfficiencyRating: 5,
    },
  });

  const [imagePreviews, setImagePreviews] = useState([]);
  const [existingImagesList, setExistingImagesList] = useState([]);

  useEffect(() => {
    const fetchExistingProduct = async () => {
      try {
        const res = await getProductById(id);
        const prod = res.data;
        if (prod) {
          setFormData({
            name: prod.name,
            brand: prod.brand,
            category: prod.category,
            description: prod.description,
            images: [], // new files
            sustainability: { ...prod.sustainability },
          });
          
          if (prod.images && prod.images.length > 0) {
            setExistingImagesList(prod.images);
          }

          if (!PREDEFINED_CATEGORIES.includes(prod.category)) {
            setIsCustomCategory(true);
          }
        }
      } catch (err) {
        setErrorMessage("Failed to fetch product details.");
      } finally {
        setIsLoading(false);
      }
    };
    fetchExistingProduct();
  }, [id]);

  const handleTextChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleSustainabilityChange = (name, value) => {
    setFormData((prev) => ({
      ...prev,
      sustainability: {
        ...prev.sustainability,
        [name]: value,
      },
    }));
  };

  const handleImageChange = (e) => {
    const files = Array.from(e.target.files);
    setFormData((prev) => ({
      ...prev,
      images: [...prev.images, ...files],
    }));

    const newPreviews = files.map((file) => URL.createObjectURL(file));
    setImagePreviews((prev) => [...prev, ...newPreviews]);
  };

  const removeNewImage = (index) => {
    setFormData((prev) => {
      const newImages = [...prev.images];
      newImages.splice(index, 1);
      return { ...prev, images: newImages };
    });

    setImagePreviews((prev) => {
      const newPreviews = [...prev];
      URL.revokeObjectURL(newPreviews[index]); // clean up
      newPreviews.splice(index, 1);
      return newPreviews;
    });
  };

  const removeExistingImage = (index) => {
      // Typically we'd keep an array of "images to delete" in state
      // For simplicity, we just filter it out visually. 
      // Fully deleting an image from cloudinary usually requires sending the public_id to backend.
      // But we will just ignore that edge case for this specific edit if it's too complex or just hide it.
      setExistingImagesList(prev => prev.filter((_, i) => i !== index));
  };


  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);
    setSuccessMessage("");
    setErrorMessage("");

    try {
      const submitData = new FormData();
      submitData.append("name", formData.name);
      submitData.append("brand", formData.brand);
      submitData.append("category", formData.category);
      submitData.append("description", formData.description);

      formData.images.forEach((img) => {
        submitData.append("images", img);
      });

      submitData.append(
        "sustainability",
        JSON.stringify(formData.sustainability)
      );

      await updateProduct(id, submitData);
      setSuccessMessage("Product updated successfully! Redirecting...");
      setTimeout(() => {
        navigate(`/products/${id}`);
      }, 1500);
    } catch (error) {
      console.error("Error updating:", error);
      setErrorMessage(
        error.response?.data?.message || "Failed to update product."
      );
    } finally {
      setIsSubmitting(false);
    }
  };

  if (isLoading) return <div className="text-center py-10"><FiLoader className="inline animate-spin w-8 h-8 text-emerald-500" /></div>;

  return (
    <form onSubmit={handleSubmit} className="space-y-8">
      {successMessage && (
        <div className="p-4 bg-emerald-50 border border-emerald-200 rounded-xl flex items-center gap-3 text-emerald-800">
          <FiCheck className="w-5 h-5" />
          <span className="font-medium">{successMessage}</span>
        </div>
      )}
      {errorMessage && (
        <div className="p-4 bg-red-50 border border-red-200 rounded-xl flex items-center gap-3 text-red-800">
          <FiX className="w-5 h-5" />
          <span className="font-medium">{errorMessage}</span>
        </div>
      )}

      {/* Grid for basic info */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div>
          <label className="block text-sm font-semibold text-gray-700 mb-1">Product Name</label>
          <input
            type="text"
            name="name"
            required
            value={formData.name}
            onChange={handleTextChange}
            className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-emerald-500 bg-gray-50/50"
          />
        </div>
        <div>
          <label className="block text-sm font-semibold text-gray-700 mb-1">Brand</label>
          <input
            type="text"
            name="brand"
            required
            value={formData.brand}
            onChange={handleTextChange}
            className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-emerald-500 bg-gray-50/50"
          />
        </div>
        <div>
          <label className="block text-sm font-semibold text-gray-700 mb-1">Category</label>
          <select
            required={!isCustomCategory}
            value={PREDEFINED_CATEGORIES.includes(formData.category) ? formData.category : (isCustomCategory ? "Other" : "")}
            onChange={(e) => {
              if (e.target.value === "Other") {
                setFormData((prev) => ({ ...prev, category: "" }));
                setIsCustomCategory(true);
              } else {
                setFormData((prev) => ({ ...prev, category: e.target.value }));
                setIsCustomCategory(false);
              }
            }}
            className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-emerald-500 bg-gray-50/50"
          >
            <option value="" disabled>Select a Category</option>
            {PREDEFINED_CATEGORIES.map(cat => (
              <option key={cat} value={cat}>{cat}</option>
            ))}
            <option value="Other">Add New Category...</option>
          </select>
          {isCustomCategory && (
            <input
              type="text"
              name="category"
              required
              value={formData.category}
              onChange={handleTextChange}
              className="mt-3 w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-emerald-500 bg-gray-50/50"
              placeholder="Type new category..."
            />
          )}
        </div>
        <div className="md:col-span-2">
          <label className="block text-sm font-semibold text-gray-700 mb-1">Description</label>
          <textarea
            name="description"
            rows={3}
            required
            value={formData.description}
            onChange={handleTextChange}
            className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-emerald-500 bg-gray-50/50 resize-none"
          />
        </div>
      </div>

      <hr className="border-gray-100" />

      {/* Image Upload Area */}
      <div>
        <label className="block text-sm font-semibold text-gray-700 mb-3">Add New Images (Appends to existing)</label>
        <div className="flex justify-center rounded-xl border border-dashed border-gray-300 px-6 py-8 bg-gray-50 hover:bg-gray-100 transition-colors mb-4">
          <div className="text-center">
            <FiUploadCloud className="mx-auto h-10 w-10 text-gray-400" />
            <label className="relative cursor-pointer rounded-md bg-transparent font-semibold text-emerald-600 focus-within:outline-none focus-within:ring-2 focus-within:ring-emerald-600 hover:text-emerald-500 mt-4 block">
              <span>Upload additional files</span>
              <input type="file" multiple accept="image/*" className="sr-only" onChange={handleImageChange} />
            </label>
          </div>
        </div>

        <div className="flex flex-col gap-2">
          <span className="text-sm font-semibold text-gray-700">Existing Images</span>
          {existingImagesList.length > 0 ? (
             <div className="grid grid-cols-2 gap-4 sm:grid-cols-4 md:grid-cols-5 mb-4">
               {existingImagesList.map((img, i) => (
                 <div key={i} className="relative group rounded-xl overflow-hidden shadow-sm border border-gray-200 h-24">
                   <img src={img.url || img} className="h-full w-full object-cover" />
                 </div>
               ))}
             </div>
          ) : <span className="text-xs text-gray-400">No existing images found.</span>}
          
          {imagePreviews.length > 0 && <span className="text-sm font-semibold text-gray-700 mt-2">New Images to Upload</span>}
          {imagePreviews.length > 0 && (
            <div className="grid grid-cols-2 gap-4 sm:grid-cols-4 md:grid-cols-5">
              {imagePreviews.map((url, i) => (
                <div key={i} className="relative group rounded-xl overflow-hidden shadow-sm border border-emerald-200 h-24">
                  <img src={url} className="h-full w-full object-cover" />
                  <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                    <button type="button" onClick={() => removeNewImage(i)} className="p-1.5 bg-red-500 text-white rounded-full"><FiX size={16} /></button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      <hr className="border-gray-100" />

      {/* Sustainability Section */}
      <div>
        <h3 className="text-xl font-bold text-gray-900 mb-6 flex items-center gap-2">
          <span className="p-1.5 bg-lime-100 text-lime-700 rounded-lg">🌱</span>
          Sustainability Metrics
        </h3>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-8">
          {[
            { key: "recyclableMaterial", label: "Recyclable Material" },
            { key: "biodegradable", label: "Biodegradable" },
            { key: "plasticFree", label: "Plastic Free" },
            { key: "crueltyFree", label: "Cruelty Free" },
            { key: "fairTradeCertified", label: "Fair Trade Certified" },
            { key: "renewableEnergyUsed", label: "Renewable Energy Used" },
          ].map((item) => (
            <div key={item.key} className="flex justify-between items-center">
              <span className="text-sm font-medium text-gray-900">{item.label}</span>
              <button
                type="button"
                className={`relative inline-flex h-6 w-11 flex-shrink-0 cursor-pointer rounded-full border-2 border-transparent transition-colors focus:ring-2 focus:ring-emerald-500 focus:ring-offset-2 ${formData.sustainability[item.key] ? "bg-emerald-600" : "bg-gray-200"}`}
                onClick={() => handleSustainabilityChange(item.key, !formData.sustainability[item.key])}
              >
                <span className={`pointer-events-none inline-block h-5 w-5 transform rounded-full bg-white shadow ring-0 transition ${formData.sustainability[item.key] ? "translate-x-5" : "translate-x-0"}`} />
              </button>
            </div>
          ))}

          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-1">Carbon Footprint (kg CO2e)</label>
            <input type="number" step="0.1" value={formData.sustainability.carbonFootprint} onChange={(e) => handleSustainabilityChange("carbonFootprint", Number(e.target.value))} className="w-full px-4 py-2.5 rounded-xl border border-gray-200 focus:ring-2 focus:ring-emerald-500 bg-gray-50/50" />
          </div>

          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-1">Energy Efficiency Rating (1-5)</label>
            <input type="number" min="1" max="5" step="1" value={formData.sustainability.energyEfficiencyRating} onChange={(e) => handleSustainabilityChange("energyEfficiencyRating", Number(e.target.value))} className="w-full px-4 py-2.5 rounded-xl border border-gray-200 focus:ring-2 focus:ring-emerald-500 bg-gray-50/50" />
          </div>
        </div>
      </div>

      <div className="pt-4">
        <button type="submit" disabled={isSubmitting} className="w-full flex items-center justify-center py-3.5 px-4 rounded-xl text-white font-semibold text-lg bg-emerald-600 hover:bg-emerald-700 transition-all shadow-md">
          {isSubmitting ? <><FiLoader className="animate-spin -ml-1 mr-2 h-5 w-5" />Updating...</> : "Update Product"}
        </button>
      </div>
    </form>
  );
}

import { createContext, useState, useCallback } from "react";

export const AuthContext = createContext(null);

/**
 * Provides global auth state (user, token, login, logout, isAuthenticated).
 * Reads the initial state from localStorage so the user stays logged in on refresh.
 */
export function AuthProvider({ children }) {
    const [token, setToken] = useState(() => localStorage.getItem("token"));
    const [user, setUser] = useState(() => {
        const stored = localStorage.getItem("user");
        return stored ? JSON.parse(stored) : null;
    });

    const login = useCallback((userData, authToken) => {
        localStorage.setItem("token", authToken);
        localStorage.setItem("user", JSON.stringify(userData));
        setToken(authToken);
        setUser(userData);
    }, []);

    const logout = useCallback(() => {
        localStorage.removeItem("token");
        localStorage.removeItem("user");
        setToken(null);
        setUser(null);
    }, []);

    const isAuthenticated = Boolean(token);

    return (
        <AuthContext.Provider value={{ user, token, login, logout, isAuthenticated }}>
            {children}
        </AuthContext.Provider>
    );
}

