import { useState, useEffect } from "react";
import { useSearchParams } from "react-router-dom";
import ComparisonSelector from "../../components/compare/ComparisonSelector";
import ComparisonResult from "../../components/compare/ComparisonResult";
import { compareProducts, quickCompareByName } from "../../services/comparisonServices";
import toast from "react-hot-toast";
import { FiLoader, FiLayers } from "react-icons/fi";

export default function ComparePage() {
  const [searchParams, setSearchParams] = useSearchParams();
  const [result, setResult] = useState(null);
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    // Handle incoming url query parameters for direct comparisons
    const p1 = searchParams.get("product1");
    const p2 = searchParams.get("product2");
    const n1 = searchParams.get("name1");
    const n2 = searchParams.get("name2");

    if (p1 && p2) {
      handleStandardCompare(p1, p2);
      // clean params from URL silently to avoid re-triggering on nav
      setSearchParams({}, { replace: true });
    } else if (n1 && n2) {
      handleQuickCompare(n1, n2);
      setSearchParams({}, { replace: true });
    }
  }, []);

  const handleStandardCompare = async (id1, id2) => {
    setIsLoading(true);
    setResult(null);
    try {
      const response = await compareProducts(id1, id2);
      if (response.success) {
        setResult(response.data);
      } else {
        toast.error(response.error || "Failed to compare products");
      }
    } catch (error) {
      console.error(error);
      const msg = error.response?.data?.error || "Error running comparison";
      toast.error(msg);
    } finally {
      setIsLoading(false);
    }
  };

  const handleQuickCompare = async (name1, name2) => {
    setIsLoading(true);
    setResult(null);
    try {
      const response = await quickCompareByName(name1, name2);
      if (response.success) {
        setResult(response.data);
      } else {
        toast.error(response.error || "Failed to compare by name");
      }
    } catch (error) {
      console.error(error);
      const is404 = error.response?.status === 404;
      const msg = is404 
        ? "No products found matching those names. Try database search." 
        : (error.response?.data?.error || "Error running quick comparison");
      toast.error(msg);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 py-12 px-4 sm:px-6 lg:px-8 font-sans">
      <div className="max-w-6xl mx-auto space-y-10">

        {/* Header */}
        <div className="text-center max-w-2xl mx-auto">
          <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-emerald-100 text-emerald-600 mb-6">
            <FiLayers className="w-8 h-8" />
          </div>
          <h1 className="text-4xl font-extrabold text-gray-900 tracking-tight mb-4">
            Compare Sustainability
          </h1>
          <p className="text-lg text-gray-600">
            Select two products to see a detailed breakdown of their ecological footprint, materials, and overall sustainability score.
          </p>
        </div>

        {/* Selector */}
        <ComparisonSelector 
          onCompare={handleStandardCompare}
          onQuickCompare={handleQuickCompare}
          isLoading={isLoading}
        />

        {/* Loading State */}
        {isLoading && (
          <div className="flex flex-col items-center justify-center py-20 text-gray-400">
            <FiLoader className="w-12 h-12 animate-spin text-emerald-500 mb-4" />
            <p className="font-medium text-lg text-gray-500">Analyzing products...</p>
            <p className="text-sm text-gray-400 mt-2 max-w-sm text-center">Our AI is compiling sustainability metrics and formatting the breakdown. This may take a few seconds.</p>
          </div>
        )}

        {/* Result */}
        {!isLoading && result && (
          <div id="comparison-result-view" className="scroll-mt-10">
             <ComparisonResult result={result} />
          </div>
        )}

      </div>
    </div>
  );
}

import { useState, useEffect } from "react";
import { useParams, Link, useNavigate } from "react-router-dom";
import ComparisonResult from "../../components/compare/ComparisonResult";
import { getComparisonById, updateComparison } from "../../services/comparisonServices";
import { FiLoader, FiArrowLeft, FiEdit3, FiSave, FiX } from "react-icons/fi";
import { useAuth } from "../../context/AuthContext";
import toast from "react-hot-toast";

export default function ComparisonDetailPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();

  const [comparison, setComparison] = useState(null);
  const [isLoading, setIsLoading] = useState(true);

  const [isEditing, setIsEditing] = useState(false);
  const [editData, setEditData] = useState({
    aiVerdict: "",
    recommendations: {
      general: [],
      product1Suggestions: [],
      product2Suggestions: []
    }
  });

  useEffect(() => {
    fetchComparison();
  }, [id]);

  const fetchComparison = async () => {
    setIsLoading(true);
    try {
      const response = await getComparisonById(id);
      if (response.success) {
        setComparison(response.data);
      } else {
        toast.error("Failed to load comparison");
        navigate("/compare/history");
      }
    } catch (error) {
      console.error(error);
      toast.error("Error loading comparison");
      navigate("/compare/history");
    } finally {
      setIsLoading(false);
    }
  };

  const handleEditToggle = () => {
    if (!isEditing && comparison) {
      // initialize edit state
      setEditData({
        aiVerdict: comparison.aiVerdict || "",
        recommendations: {
          general: comparison.recommendations?.general || [],
          product1Suggestions: comparison.recommendations?.product1Suggestions || [],
          product2Suggestions: comparison.recommendations?.product2Suggestions || []
        }
      });
    }
    setIsEditing(!isEditing);
  };

  const handleArrayChange = (field, subfield, value) => {
    // split by new lines for simple array editing
    const arr = value.split('\n').filter(line => line.trim() !== '');
    setEditData({
      ...editData,
      [field]: {
        ...editData[field],
        [subfield]: arr
      }
    });
  };

  const handleSave = async () => {
    setIsLoading(true);
    try {
      const response = await updateComparison(id, editData);
      if (response.success) {
        toast.success("Comparison updated successfully");
        setComparison(response.data);
        setIsEditing(false);
      } else {
        toast.error("Failed to update comparison");
      }
    } catch (error) {
      console.error(error);
      toast.error(error.response?.data?.error || "Error updating comparison");
    } finally {
      setIsLoading(false);
    }
  };

  const isAdmin = user?.role === "Admin";

  if (isLoading && !comparison) {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center">
        <FiLoader className="w-12 h-12 animate-spin text-emerald-500 mb-4" />
        <p className="font-medium text-gray-500">Loading comparison details...</p>
      </div>
    );
  }

  if (!comparison) return null;

  return (
    <div className="min-h-screen bg-gray-50 py-12 px-4 sm:px-6 lg:px-8 font-sans">
      <div className="max-w-6xl mx-auto space-y-6">

        {/* Header Actions */}
        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
          <Link to="/compare/history" className="inline-flex items-center gap-2 text-sm font-medium text-gray-500 hover:text-emerald-600 transition-colors">
            <FiArrowLeft /> Back to History
          </Link>

          {isAdmin && (
            <div className="flex items-center gap-3">
              {!isEditing ? (
                <button
                  onClick={handleEditToggle}
                  className="px-4 py-2 bg-indigo-50 hover:bg-indigo-100 text-indigo-700 rounded-lg font-medium transition-colors flex items-center gap-2 text-sm"
                >
                  <FiEdit3 /> Edit AI & Recommendations (Admin)
                </button>
              ) : (
                <>
                  <button
                    onClick={handleEditToggle}
                    className="px-4 py-2 bg-gray-100 hover:bg-gray-200 text-gray-700 rounded-lg font-medium transition-colors flex items-center gap-2 text-sm"
                  >
                    <FiX /> Cancel
                  </button>
                  <button
                    onClick={handleSave}
                    disabled={isLoading}
                    className="px-4 py-2 bg-emerald-600 hover:bg-emerald-700 text-white rounded-lg font-bold transition-colors flex items-center gap-2 text-sm"
                  >
                    {isLoading ? <FiLoader className="animate-spin" /> : <FiSave />} Save Changes
                  </button>
                </>
              )}
            </div>
          )}
        </div>

        {/* Edit Form overrides result display visually if editing */}
        {isEditing ? (
          <div className="bg-white rounded-2xl shadow-sm border border-indigo-200 p-8 space-y-6">
            <div className="flex items-center gap-2 text-indigo-800 mb-6 pb-4 border-b border-indigo-100">
               <FiEdit3 className="w-6 h-6" />
               <h2 className="text-xl font-bold">Admin Edit Mode</h2>
            </div>

            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">AI Verdict</label>
              <textarea
                value={editData.aiVerdict}
                onChange={(e) => setEditData({...editData, aiVerdict: e.target.value})}
                rows={4}
                className="w-full p-4 rounded-xl border border-gray-200 focus:ring-2 focus:ring-indigo-500 focus:outline-none bg-gray-50"
              />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-2">General Recommendations (1 per line)</label>
                <textarea
                  value={editData.recommendations.general.join('\n')}
                  onChange={(e) => handleArrayChange('recommendations', 'general', e.target.value)}
                  rows={6}
                  className="w-full p-4 rounded-xl border border-gray-200 focus:ring-2 focus:ring-indigo-500 focus:outline-none bg-gray-50"
                />
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-2">Product 1 Suggestions</label>
                <textarea
                  value={editData.recommendations.product1Suggestions.join('\n')}
                  onChange={(e) => handleArrayChange('recommendations', 'product1Suggestions', e.target.value)}
                  rows={6}
                  className="w-full p-4 rounded-xl border border-gray-200 focus:ring-2 focus:ring-emerald-500 focus:outline-none bg-emerald-50/30"
                />
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-2">Product 2 Suggestions</label>
                <textarea
                  value={editData.recommendations.product2Suggestions.join('\n')}
                  onChange={(e) => handleArrayChange('recommendations', 'product2Suggestions', e.target.value)}
                  rows={6}
                  className="w-full p-4 rounded-xl border border-gray-200 focus:ring-2 focus:ring-indigo-500 focus:outline-none bg-indigo-50/30"
                />
              </div>
            </div>
          </div>
        ) : (
          <ComparisonResult result={comparison} id={id} />
        )}

      </div>
    </div>
  );
}

import { useEffect, useRef, useState } from "react";
import { useAuth } from "../../hooks/useAuth";
import { useNavigate, Link } from "react-router-dom";
import toast from "react-hot-toast";
import { getMyBlogs } from "../../services/blogService";

export default function HomePage() {
    const { user, logout, isAuthenticated } = useAuth();
    const navigate = useNavigate();
    const [myBlogs, setMyBlogs] = useState([]);
    const [notifications, setNotifications] = useState([]);
    const [showNotificationPanel, setShowNotificationPanel] = useState(false);
    const notificationRef = useRef(null);

    useEffect(() => {
        const fetchMyBlogs = async () => {
            if (!isAuthenticated) return;
            try {
                const data = await getMyBlogs({ page: 1, limit: 20 });
                setMyBlogs(data?.blogs || []);

                // Build notifications from blogs
                const rejected = data?.blogs?.filter((blog) => blog.status === "REJECTED") || [];
                const approved = data?.blogs?.filter((blog) => blog.status === "PUBLISHED") || [];
                
                const notificationsList = [];
                
                // Add rejection notifications
                rejected.forEach((blog) => {
                    notificationsList.push({
                        id: `rejection-${blog._id}`,
                        type: "rejection",
                        title: blog.title,
                        message: blog.rejectionReason || "No reason provided",
                        timestamp: blog.updatedAt,
                        read: false,
                    });
                });
                
                // Add approval notifications
                approved.forEach((blog) => {
                    notificationsList.push({
                        id: `approval-${blog._id}`,
                        type: "approval",
                        title: blog.title,
                        message: "Your blog has been approved and published!",
                        timestamp: blog.approvedAt,
                        read: false,
                    });
                });

                setNotifications(notificationsList);
            } catch {
                // ignore optional account notification errors
            }
        };

        fetchMyBlogs();
    }, [isAuthenticated]);

    // Close notification panel when clicking outside
    useEffect(() => {
        const handleClickOutside = (event) => {
            if (notificationRef.current && !notificationRef.current.contains(event.target)) {
                setShowNotificationPanel(false);
            }
        };

        if (showNotificationPanel) {
            document.addEventListener("mousedown", handleClickOutside);
        }

        return () => {
            document.removeEventListener("mousedown", handleClickOutside);
        };
    }, [showNotificationPanel]);

    const dismissNotification = (id) => {
        setNotifications(notifications.filter((notif) => notif.id !== id));
    };

    const handleLogout = () => {
        logout();
        toast.success("Logged out successfully");
        navigate("/login");
    };

    return (
        <div className="min-h-screen bg-linear-to-br from-blue-50 to-indigo-100">
            {/* Navigation Bar */}
            <nav className="bg-white shadow-md">
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                    <div className="flex justify-between items-center h-16">
                        <div className="flex items-center">
                            <h1 className="text-2xl font-bold text-indigo-600">
                                Sustainable Products
                            </h1>
                        </div>
                        <div className="flex items-center gap-4">
                            {isAuthenticated ? (
                                <>
                                    <span className="text-gray-700">
                                        Welcome, <span className="font-semibold">{user?.name}</span>
                                    </span>

                                    {/* Notification Button */}
                                    <div className="relative" ref={notificationRef}>
                                        <button
                                            onClick={() => setShowNotificationPanel(!showNotificationPanel)}
                                            className="relative p-2 text-gray-600 hover:text-indigo-600 transition-colors"
                                            title="Notifications"
                                        >
                                            <svg
                                                className="w-6 h-6"
                                                fill="none"
                                                stroke="currentColor"
                                                viewBox="0 0 24 24"
                                            >
                                                <path
                                                    strokeLinecap="round"
                                                    strokeLinejoin="round"
                                                    strokeWidth={2}
                                                    d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9"
                                                />
                                            </svg>
                                            {notifications.length > 0 && (
                                                <span className="absolute top-0 right-0 inline-flex items-center justify-center px-2 py-1 text-xs font-bold leading-none text-white transform translate-x-1/2 -translate-y-1/2 bg-red-600 rounded-full">
                                                    {notifications.length}
                                                </span>
                                            )}
                                        </button>

                                        {/* Notification Dropdown Panel */}
                                        {showNotificationPanel && (
                                            <div className="absolute right-0 mt-2 w-80 bg-white rounded-lg shadow-xl z-50 max-h-96 overflow-y-auto">
                                                <div className="sticky top-0 bg-indigo-50 px-4 py-3 border-b">
                                                    <h3 className="text-sm font-bold text-gray-900">
                                                        Notifications ({notifications.length})
                                                    </h3>
                                                </div>

                                                {notifications.length > 0 ? (
                                                    <div className="divide-y">
                                                        {notifications.map((notif) => (
                                                            <div
                                                                key={notif.id}
                                                                className={`px-4 py-3 hover:bg-gray-50 transition-colors ${
                                                                    notif.type === "rejection"
                                                                        ? "border-l-4 border-l-red-500"
                                                                        : "border-l-4 border-l-green-500"
                                                                }`}
                                                            >
                                                                <div className="flex items-start justify-between gap-2">
                                                                    <div className="flex-1 min-w-0">
                                                                        <div className="flex items-center gap-2 mb-1">
                                                                            {notif.type === "rejection" ? (
                                                                                <span className="text-lg">❌</span>
                                                                            ) : (
                                                                                <span className="text-lg">✅</span>
                                                                            )}
                                                                            <p className="text-sm font-semibold text-gray-900 truncate">
                                                                                {notif.title}
                                                                            </p>
                                                                        </div>
                                                                        <p
                                                                            className={`text-xs leading-relaxed ${
                                                                                notif.type === "rejection"
                                                                                    ? "text-red-700"
                                                                                    : "text-green-700"
                                                                            }`}
                                                                        >
                                                                            {notif.message}
                                                                        </p>
                                                                    </div>
                                                                    <button
                                                                        onClick={() =>
                                                                            dismissNotification(notif.id)
                                                                        }
                                                                        className="text-gray-400 hover:text-gray-600 flex-shrink-0"
                                                                        title="Dismiss"
                                                                    >
                                                                        ✕
                                                                    </button>
                                                                </div>
                                                            </div>
                                                        ))}
                                                    </div>
                                                ) : (
                                                    <div className="px-4 py-6 text-center text-gray-500 text-sm">
                                                        No notifications yet
                                                    </div>
                                                )}
                                            </div>
                                        )}
                                    </div>

                                    <Link
                                        to="/blogs"
                                        className="px-4 py-2 bg-slate-100 text-slate-700 rounded-lg hover:bg-slate-200 transition-colors"
                                    >
                                        Blog Feed
                                    </Link>
                                    <Link
                                        to="/blogs/create"
                                        className="px-4 py-2 bg-emerald-500 text-white rounded-lg hover:bg-emerald-600 transition-colors"
                                    >
                                        Create Blog
                                    </Link>
                                    {user?.role === "Admin" && (
                                        <Link
                                            to="/admin/dashboard"
                                            className="px-4 py-2 bg-indigo-500 text-white rounded-lg hover:bg-indigo-600 transition-colors"
                                        >
                                            Admin Dashboard
                                        </Link>
                                    )}
                                    <button
                                        onClick={handleLogout}
                                        className="px-4 py-2 bg-red-500 text-white rounded-lg hover:bg-red-600 transition-colors"
                                    >
                                        Logout
                                    </button>
                                </>
                            ) : (
                                <>
                                    <Link
                                        to="/blogs"
                                        className="px-4 py-2 text-emerald-700 hover:text-emerald-800 font-semibold transition-colors"
                                    >
                                        Blog Feed
                                    </Link>
                                    <Link
                                        to="/login"
                                        className="px-4 py-2 text-indigo-600 hover:text-indigo-800 font-semibold transition-colors"
                                    >
                                        Login
                                    </Link>
                                    <Link
                                        to="/register"
                                        className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors"
                                    >
                                        Sign Up
                                    </Link>
                                </>
                            )}
                        </div>
                    </div>
                </div>
            </nav>

            {/* Main Content */}
            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
                <div className="text-center mb-12">
                    <h2 className="text-4xl font-bold text-gray-900 mb-4">
                        {isAuthenticated 
                            ? `Welcome to Your Dashboard, ${user?.name}!` 
                            : "Welcome to Sustainable Products"}
                    </h2>
                    <p className="text-xl text-gray-600">
                        Discover and rate sustainable products
                    </p>
                    {!isAuthenticated && (
                        <div className="mt-6">
                            <Link
                                to="/register"
                                className="inline-block px-8 py-3 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors font-semibold text-lg"
                            >
                                Get Started Today
                            </Link>
                        </div>
                    )}
                </div>

                {/* Feature Cards */}
                <div className="grid md:grid-cols-3 gap-8 mb-12">
                    <div className="bg-white rounded-xl shadow-lg p-6 hover:shadow-xl transition-shadow">
                        <div className="text-4xl mb-4">🌿</div>
                        <h3 className="text-xl font-bold text-gray-900 mb-2">
                            Eco-Friendly Products
                        </h3>
                        <p className="text-gray-600">
                            Browse thousands of environmentally conscious products
                        </p>
                    </div>

                    <div className="bg-white rounded-xl shadow-lg p-6 hover:shadow-xl transition-shadow">
                        <div className="text-4xl mb-4">⭐</div>
                        <h3 className="text-xl font-bold text-gray-900 mb-2">
                            Rate Products
                        </h3>
                        <p className="text-gray-600">
                            Share your experience and help others make informed choices
                        </p>
                    </div>

                    <div className="bg-white rounded-xl shadow-lg p-6 hover:shadow-xl transition-shadow">
                        <div className="text-4xl mb-4">📊</div>
                        <h3 className="text-xl font-bold text-gray-900 mb-2">
                            View Analytics
                        </h3>
                        <p className="text-gray-600">
                            Track your contributions to sustainable living
                        </p>
                    </div>
                </div>

                {/* User Info Card - Only show when authenticated */}
                {isAuthenticated && (
                    <div className="bg-white rounded-xl shadow-lg p-8">
                        <h3 className="text-2xl font-bold text-gray-900 mb-4">
                            Your Profile
                        </h3>
                        <div className="grid md:grid-cols-2 gap-4">
                            <div>
                                <p className="text-gray-600">Name</p>
                                <p className="text-lg font-semibold text-gray-900">{user?.name}</p>
                            </div>
                            <div>
                                <p className="text-gray-600">Email</p>
                                <p className="text-lg font-semibold text-gray-900">{user?.email}</p>
                            </div>
                            <div>
                                <p className="text-gray-600">Role</p>
                                <p className="text-lg font-semibold text-gray-900">{user?.role}</p>
                            </div>
                            <div>
                                <p className="text-gray-600">Account Status</p>
                                <span className="inline-block px-3 py-1 bg-green-100 text-green-800 rounded-full text-sm font-semibold">
                                    Active
                                </span>
                            </div>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
}

import { useEffect, useState, useContext } from "react";
import { useParams, Link, useNavigate } from "react-router-dom";
import { getProductById, deleteProduct } from "../../services/productServices";
import { AuthContext } from "../../context/AuthContext";
import toast from "react-hot-toast";
import { 
  FiArrowLeft, FiLoader, FiCheck, FiX, 
  FiBox, FiActivity, FiCpu, FiAlertCircle, FiEdit, FiTrash2 
} from "react-icons/fi";

export default function ProductDetailsPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useContext(AuthContext);

  const [product, setProduct] = useState(null);
  const [loading, setLoading] = useState(true);
  const [selectedImage, setSelectedImage] = useState("");

  useEffect(() => {
    const fetchProduct = async () => {
      try {
        const response = await getProductById(id);
        if (response.success && response.data) {
          setProduct(response.data);
          if (response.data.images?.length > 0) {
            setSelectedImage(response.data.images[0].url || response.data.images[0]);
          }
        }
      } catch (error) {
        console.error("Error fetching product details:", error);
      } finally {
        setLoading(false);
      }
    };
    fetchProduct();
  }, [id]);

  const handleDelete = async () => {
    if (window.confirm("Are you sure you want to delete this product? This action cannot be undone.")) {
      try {
        await deleteProduct(id);
        toast.success("Product deleted successfully");
        navigate("/products");
      } catch (err) {
        toast.error("Failed to delete product");
      }
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col justify-center items-center">
        <FiLoader className="w-12 h-12 text-emerald-500 animate-spin mb-4" />
        <p className="text-gray-500 text-lg font-medium">Loading Product Details...</p>
      </div>
    );
  }

  if (!product) {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col justify-center items-center">
        <FiAlertCircle className="w-16 h-16 text-yellow-500 mb-6" />
        <h2 className="text-2xl font-bold text-gray-800 mb-2">Product Not Found</h2>
        <p className="text-gray-500 mb-6 max-w-md text-center">
          We couldn't find the requested product. It might have been removed or the link is incorrect.
        </p>
        <Link to="/products" className="px-6 py-2 bg-emerald-600 font-semibold text-white rounded-xl shadow-md">
          Back to Catalog
        </Link>
      </div>
    );
  }

  const defaultImage = "https://via.placeholder.com/600x400?text=No+Image+Available";
  
  // Format boolean feature rows
  const FeatureRow = ({ label, isTrue }) => (
    <div className="flex justify-between items-center py-2.5 border-b border-gray-100 last:border-0">
      <span className="text-gray-600">{label}</span>
      <div className="flex items-center gap-1.5 font-medium">
        {isTrue ? (
          <><FiCheck className="text-emerald-500 w-4 h-4" /><span className="text-emerald-700">Yes</span></>
        ) : (
          <><FiX className="text-red-400 w-4 h-4" /><span className="text-red-500">No</span></>
        )}
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-gray-50 py-10 px-4 sm:px-6 lg:px-8 font-sans">
      <div className="max-w-6xl mx-auto">
        <div className="flex justify-between items-center mb-8 gap-4 flex-wrap">
          <Link 
            to="/products" 
            className="inline-flex items-center text-sm font-medium text-emerald-600 hover:text-emerald-500 transition-colors"
          >
            <FiArrowLeft className="mr-2" /> Back to Products
          </Link>

          {user?.role === "Admin" && (
            <div className="flex gap-3">
              <Link 
                to={`/edit-product/${id}`}
                className="flex items-center gap-2 px-4 py-2 bg-indigo-50 text-indigo-700 hover:bg-indigo-100 rounded-lg font-medium transition-colors shadow-sm"
              >
                <FiEdit /> Edit Product
              </Link>
              <button 
                onClick={handleDelete}
                className="flex items-center gap-2 px-4 py-2 bg-red-50 text-red-700 hover:bg-red-100 rounded-lg font-medium transition-colors shadow-sm"
              >
                <FiTrash2 /> Delete Product
              </button>
            </div>
          )}
        </div>
        
        <div className="bg-white rounded-3xl shadow-lg border border-gray-100 overflow-hidden">
          <div className="grid grid-cols-1 lg:grid-cols-2">
            
            {/* Left: Interactive Image Gallery */}
            <div className="p-8 lg:p-10 bg-gray-50/50 flex flex-col justify-center border-r border-gray-100">
              <div className="aspect-square bg-white rounded-2xl border border-gray-200 overflow-hidden mb-6 flex items-center justify-center shadow-inner">
                <img 
                  src={selectedImage || defaultImage} 
                  alt={product.name} 
                  className="w-full h-full object-contain p-4"
                />
              </div>

              {/* Thumbnails */}
              {product.images?.length > 1 && (
                <div className="flex gap-4 overflow-x-auto pb-2 custom-scrollbar">
                  {product.images.map((img, idx) => {
                    const imgUrl = img.url || img;
                    return (
                      <button 
                        key={idx}
                        onClick={() => setSelectedImage(imgUrl)}
                        className={`relative w-20 h-20 flex-shrink-0 rounded-xl overflow-hidden border-2 transition-all ${selectedImage === imgUrl ? 'border-emerald-500 shadow-md ring-2 ring-emerald-100' : 'border-gray-200 opacity-60 hover:opacity-100'}`}
                      >
                         <img src={imgUrl} className="w-full h-full object-cover" alt="Thumbnail" />
                      </button>
                    );
                  })}
                </div>
              )}
            </div>

            {/* Right: Info Section */}
            <div className="p-8 lg:p-10 flex flex-col">
              <div className="mb-8">
                <div className="flex items-center gap-3 mb-3 text-sm">
                  <span className="font-bold text-emerald-600 tracking-widest uppercase">{product.brand}</span>
                  <span className="w-1.5 h-1.5 bg-gray-300 rounded-full"></span>
                  <span className="text-gray-500">{product.category}</span>
                </div>
                <h1 className="text-4xl font-extrabold text-gray-900 mb-4 leading-tight">{product.name}</h1>
                <p className="text-lg text-gray-600 leading-relaxed min-h-[4rem]">
                  {product.description}
                </p>
              </div>

              <div className="grid sm:grid-cols-2 gap-6 mb-10">
                {/* Score Widget */}
                <div className="bg-gradient-to-br from-emerald-50 to-teal-50 rounded-2xl p-6 border border-emerald-100 shadow-sm flex flex-col items-center justify-center text-center">
                   <FiActivity className="text-emerald-500 w-8 h-8 mb-2" />
                   <h3 className="text-sm font-bold text-emerald-800 uppercase tracking-widest">Sustainability Score</h3>
                   <div className="text-5xl font-black text-emerald-600 mt-2">
                     {Math.round(product.sustainabilityScore)}<span className="text-2xl text-emerald-400 font-bold">/100</span>
                   </div>
                </div>

                {/* Optional AI Widget */}
                {product.aiSustainablityScore > 0 && (
                  <div className="bg-gradient-to-br from-indigo-50 to-purple-50 rounded-2xl p-6 border border-indigo-100 shadow-sm flex flex-col items-center justify-center text-center">
                     <FiCpu className="text-indigo-500 w-8 h-8 mb-2" />
                     <h3 className="text-sm font-bold text-indigo-800 uppercase tracking-widest">AI Evaluated Trust</h3>
                     <div className="text-5xl font-black text-indigo-600 mt-2">
                       {Math.round(product.aiSustainablityScore)}<span className="text-2xl text-indigo-400 font-bold">/100</span>
                     </div>
                  </div>
                )}
              </div>

              {/* Sustainability Matrix */}
              <div className="bg-white rounded-2xl border border-gray-200 p-6 flex-grow">
                <h3 className="text-xl font-bold text-gray-900 flex items-center gap-2 mb-6">
                  <FiBox className="text-gray-400" /> Sustainability Data
                </h3>
                
                <div className="grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-1">
                   <FeatureRow label="Recyclable Material" isTrue={product.sustainability?.recyclableMaterial} />
                   <FeatureRow label="Biodegradable" isTrue={product.sustainability?.biodegradable} />
                   <FeatureRow label="Plastic-Free" isTrue={product.sustainability?.plasticFree} />
                   <FeatureRow label="Cruelty-Free" isTrue={product.sustainability?.crueltyFree} />
                   <FeatureRow label="Fair Trade Certified" isTrue={product.sustainability?.fairTradeCertified} />
                   <FeatureRow label="Renewable Energy Used" isTrue={product.sustainability?.renewableEnergyUsed} />
                </div>

                <div className="mt-6 pt-5 border-t border-gray-100 flex justify-between bg-gray-50 -mx-6 -mb-6 p-6 rounded-b-2xl">
                   <div>
                     <span className="block text-sm text-gray-500 font-medium">Carbon Footprint</span>
                     <span className="font-bold text-gray-900 text-lg">{product.sustainability?.carbonFootprint} kg</span> CO₂e
                   </div>
                   <div className="text-right">
                     <span className="block text-sm text-gray-500 font-medium">Energy Efficiency</span>
                     <span className="font-bold text-gray-900 text-lg">{product.sustainability?.energyEfficiencyRating}</span> / 5
                   </div>
                </div>
              </div>
            </div>
          </div>
          
          {/* AI Description Panel */}
          {product.aiSustainabilityDescription && (
             <div className="bg-indigo-900 text-indigo-50 p-8 lg:p-12 border-t flex flex-col lg:flex-row gap-8 items-center bg-[url('https://www.transparenttextures.com/patterns/cubes.png')]">
                <div className="lg:w-1/4 flex flex-col items-center text-center">
                   <div className="w-16 h-16 bg-white/10 rounded-full flex items-center justify-center mb-4">
                      <FiCpu className="w-8 h-8 text-indigo-300" />
                   </div>
                   <h3 className="text-lg font-bold text-white tracking-widest uppercase">AI Insight</h3>
                   <p className="text-indigo-300 text-sm mt-1">Automated environmental analysis</p>
                </div>
                <div className="lg:w-3/4">
                  <p className="text-xl leading-relaxed font-serif text-indigo-100 italic">
                    "{product.aiSustainabilityDescription}"
                  </p>
                </div>
             </div>
          )}
          
        </div>
      </div>
    </div>
  );
}
